import hou
import os

# kwargs['work_items'] is passed automatically by the menu context
selected_items = kwargs.get('work_items', [])

if selected_items:
    # We focus on the first selected item to avoid opening 50 windows
    work_item = selected_items[0]

    file_path = None

    # Priority 1: Check if the item is cooked and has Result Data
    if work_item.resultData:
        # Get the first output file
        file_path = work_item.resultData[0].path

    # Priority 2: If not cooked, check for Expected Output
    elif work_item.expectedOutputPaths:
        file_path = work_item.expectedOutputPaths[0]

    # Priority 3: Fallback to common attribute names (useful for uncached generic items)
    elif work_item.attribs.has("file"):
        file_path = work_item.attribs["file"].value()
    elif work_item.attribs.has("output"):
        file_path = work_item.attribs["output"].value()

    if file_path:
        # Ensure the path is absolute and variables are expanded
        # (PDG usually handles this, but safety first)
        if not os.path.isabs(file_path):
            # Attempt to locate relative to HIP if not absolute
            file_path = hou.text.expandString(file_path)

        # Check if file exists to decide logic
        if os.path.exists(file_path):
            # This function opens the folder and highlights the specific file
            hou.ui.showInFileBrowser(file_path)
        else:
            # If the file doesn't exist yet (not cooked), try opening the directory
            dir_path = os.path.dirname(file_path)
            if os.path.exists(dir_path):
                hou.ui.showInFileBrowser(dir_path)
            else:
                hou.ui.setStatusMessage("TOPs: Output directory does not exist yet.", severity=hou.severityType.Warning)
    else:
        hou.ui.setStatusMessage("TOPs: No output path found on this work item.", severity=hou.severityType.Warning)
